<template>
	<view 
		v-if="showPopup" 
		class="uv-popup" 
		:class="[popupClass, isDesktop ? 'fixforpc-z-index' : '']"
		:style="[{zIndex: zIndex}]"
	>
		<view @touchstart="touchstart">
			<!-- йҒ®зҪ©еұӮ -->
			<uv-overlay
				key="1"
				v-if="maskShow && overlay"
				:show="showTrans"
				:duration="duration"
				:custom-style="overlayStyle"
				:opacity="overlayOpacity"
			  :zIndex="zIndex"
				@click="onTap"
			></uv-overlay>
			<uv-transition 
				key="2" 
				:mode="ani" 
				name="content" 
				:custom-style="transitionStyle" 
				:duration="duration"
				:show="showTrans" 
				@click="onTap"
			>
				<view 
					class="uv-popup__content" 
					:style="[contentStyle]" 
					:class="[popupClass]" 
					@click="clear"
				>
					<uv-status-bar v-if="safeAreaInsetTop"></uv-status-bar>
					<slot />
					<uv-safe-bottom v-if="safeAreaInsetBottom"></uv-safe-bottom>
					<view
						v-if="closeable"
						@tap.stop="close"
						class="uv-popup__content__close"
						:class="['uv-popup__content__close--' + closeIconPos]"
						hover-class="uv-popup__content__close--hover"
						hover-stay-time="150"
					>
						<uv-icon
							name="close"
							color="#909399"
							size="18"
							bold
						></uv-icon>
					</view>
				</view>
			</uv-transition>
		</view>



	</view>
</template>

<script lang="uts">



	import mpMixin from '@/uni_modules/uv-ui-tools/libs/mixin/mpMixin.js'
	import mixin from '@/uni_modules/uv-ui-tools/libs/mixin/mixin.js'
	/**
	* PopUp еј№еҮәеұӮ
	* @description еј№еҮәеұӮз»„д»¶пјҢдёәдәҶи§ЈеҶійҒ®зҪ©еј№еұӮзҡ„й—®йўҳ
	* @tutorial https://www.uvui.cn/components/popup.html
	* @property {String} mode = [top|center|bottom|left|right] еј№еҮәж–№ејҸ
	* 	@value top йЎ¶йғЁеј№еҮә
	* 	@value center дёӯй—ҙеј№еҮә
	* 	@value bottom еә•йғЁеј№еҮә
	* 	@value left		е·Ұдҫ§еј№еҮә
	* 	@value right  еҸідҫ§еј№еҮә
	* @property {Number} duration еҠЁз”»ж—¶й•ҝпјҢй»ҳи®Ө300
	* @property {Boolean} overlay жҳҜеҗҰжҳҫзӨәйҒ®зҪ©пјҢй»ҳи®Өtrue
	* @property {Boolean} overlayOpacity йҒ®зҪ©йҖҸжҳҺеәҰпјҢй»ҳи®Ө0.5 
	* @property {Object} overlayStyle йҒ®зҪ©иҮӘе®ҡд№үж ·ејҸ
	* @property {Boolean} closeOnClickOverlay = [true|false] и’ҷзүҲзӮ№еҮ»жҳҜеҗҰе…ій—ӯеј№зӘ—пјҢй»ҳи®Өtrue
	* @property {Number | String} zIndex еј№еҮәеұӮзҡ„еұӮзә§
	* @property {Boolean} safeAreaInsetTop жҳҜеҗҰз•ҷеҮәйЎ¶йғЁе®үе…ЁеҢәпјҲзҠ¶жҖҒж Ҹй«ҳеәҰпјүпјҢй»ҳи®Өfalse
	* @property {Boolean} safeAreaInsetBottom жҳҜеҗҰдёәз•ҷеҮәеә•йғЁе®үе…ЁеҢәйҖӮй…ҚпјҢй»ҳи®Өtrue
	* @property {Boolean} closeable жҳҜеҗҰжҳҫзӨәе…ій—ӯеӣҫж ҮпјҢй»ҳи®Өfalse
	* @property {Boolean} closeIconPos иҮӘе®ҡд№үе…ій—ӯеӣҫж ҮдҪҚзҪ®пјҢ`top-left`-е·ҰдёҠи§’пјҢ`top-right`-еҸідёҠи§’пјҢ`bottom-left`-е·ҰдёӢи§’пјҢ`bottom-right`-еҸідёӢи§’пјҢй»ҳи®Өtop-right
	* @property {String}  bgColor дё»зӘ—еҸЈиғҢжҷҜиүІ
	* @property {String}  maskBackgroundColor и’ҷзүҲйўңиүІ
	* @property {Boolean} customStyle иҮӘе®ҡд№үж ·ејҸ
	* @event {Function} change жү“ејҖе…ій—ӯеј№зӘ—и§ҰеҸ‘пјҢe={show: false}
	* @event {Function} maskClick зӮ№еҮ»йҒ®зҪ©и§ҰеҸ‘
	*/
	export default {
		name: 'uv-popup',
		components: {



		},
		mixins: [mpMixin, mixin],
		emits: ['change', 'maskClick'],
		props: {
			// еј№еҮәеұӮзұ»еһӢпјҢеҸҜйҖүеҖјпјҢtop: йЎ¶йғЁеј№еҮәеұӮпјӣbottomпјҡеә•йғЁеј№еҮәеұӮпјӣcenterпјҡе…ЁеұҸеј№еҮәеұӮ
			// message: ж¶ҲжҒҜжҸҗзӨә ; dialog : еҜ№иҜқжЎҶ
			mode: {
				type: String,
				default: 'center'
			},
			// еҠЁз”»ж—¶й•ҝпјҢеҚ•дҪҚms
			duration: {
				type: [String, Number],
				default: 300
			},
			// еұӮзә§
			zIndex: {
				type: [String, Number],




				default: 10075

			},
			bgColor: {
				type: String,
				default: '#ffffff'
			},
			safeArea: {
				type: Boolean,
				default: true
			},
			// жҳҜеҗҰжҳҫзӨәйҒ®зҪ©
			overlay: {
				type: Boolean,
				default: true
			},
			// зӮ№еҮ»йҒ®зҪ©жҳҜеҗҰе…ій—ӯеј№зӘ—
			closeOnClickOverlay: {
				type: Boolean,
				default: true
			},
			// йҒ®зҪ©зҡ„йҖҸжҳҺеәҰпјҢ0-1д№Ӣй—ҙ
			overlayOpacity: {
				type: [Number, String],
				default: 0.4
			},
			// иҮӘе®ҡд№үйҒ®зҪ©зҡ„ж ·ејҸ
			overlayStyle: {
				type: [Object, String],
				default: ''
			},
			// жҳҜеҗҰдёәiPhoneXз•ҷеҮәеә•йғЁе®үе…Ёи·қзҰ»
			safeAreaInsetBottom: {
				type: Boolean,
				default: true
			},
			// жҳҜеҗҰз•ҷеҮәйЎ¶йғЁе®үе…Ёи·қзҰ»пјҲзҠ¶жҖҒж Ҹй«ҳеәҰпјү
			safeAreaInsetTop: {
				type: Boolean,
				default: false
			},
			// жҳҜеҗҰжҳҫзӨәе…ій—ӯеӣҫж Ү
			closeable: {
				type: Boolean,
				default: false
			},
			// иҮӘе®ҡд№үе…ій—ӯеӣҫж ҮдҪҚзҪ®пјҢtop-leftдёәе·ҰдёҠи§’пјҢtop-rightдёәеҸідёҠи§’пјҢbottom-leftдёәе·ҰдёӢи§’пјҢbottom-rightдёәеҸідёӢи§’
			closeIconPos: {
				type: String,
				default: 'top-right'
			},
			// mode=centerпјҢд№ҹеҚідёӯйғЁеј№еҮәж—¶пјҢжҳҜеҗҰдҪҝз”Ёзј©ж”ҫжЁЎејҸ
			zoom: {
				type: Boolean,
				default: true
			},
			round: {
				type: [Number, String],
				default: 0
			},
			...uni.$uv?.props?.popup
		},
		watch: {
			/**
			 * зӣ‘еҗ¬typeзұ»еһӢ
			 */
			type: {
				handler: function(type) {
					if (!this.config[type]) return
					this[this.config[type]](true)
				},
				immediate: true
			},
			isDesktop: {
				handler: function(newVal) {
					if (!this.config[newVal]) return
					this[this.config[this.mode]](true)
				},
				immediate: true
			},
			// H5 дёӢзҰҒжӯўеә•йғЁж»ҡеҠЁ
			showPopup(show) {




			}
		},
		data() {
			return {
				ani: [],
				showPopup: false,
				showTrans: false,
				popupWidth: 0,
				popupHeight: 0,
				config: {
					top: 'top',
					bottom: 'bottom',
					center: 'center',
					left: 'left',
					right: 'right',
					message: 'top',
					dialog: 'center',
					share: 'bottom'
				},
				transitionStyle: {
					position: 'fixed',
					left: 0,
					right: 0
				},
				maskShow: true,
				mkclick: true,
				popupClass: this.isDesktop ? 'fixforpc-top' : 'top',
				direction: ''
			}
		},
		computed: {
			isDesktop() {
				return this.popupWidth >= 500 && this.popupHeight >= 500
			},
			bg() {
				if (this.bgColor === '' || this.bgColor === 'none' || this.$uv.getPx(this.round)>0) {
					return 'transparent'
				}
				return this.bgColor
			},
			contentStyle() {
				const style = {};
				if (this.bgColor) {
					style.backgroundColor = this.bg
				}
				if(this.round) {
					const value = this.$uv.addUnit(this.round)
					const mode = this.direction?this.direction:this.mode
					style.backgroundColor = this.bgColor
					if(mode === 'top') {
						style.borderBottomLeftRadius = value
						style.borderBottomRightRadius = value
					} else if(mode === 'bottom') {
						style.borderTopLeftRadius = value
						style.borderTopRightRadius = value
					} else if(mode === 'center') {
						style.borderRadius = value
					} 
				}
				return this.$uv.deepMerge(style, this.$uv.addStyle(this.customStyle))
			}
		},







		// TODO vue3
		unmounted() {
			this.setH5Visible()
		},

		created() {
			// TODO еӨ„зҗҶ message з»„д»¶з”ҹе‘Ҫе‘ЁжңҹејӮеёёзҡ„й—®йўҳ
			this.messageChild = null
			// TODO и§ЈеҶіеӨҙжқЎеҶ’жіЎзҡ„й—®йўҳ
			this.clearPropagation = false
		},
		methods: {
			setH5Visible() {




			},
			/**
			 * е…¬з”Ёж–№жі•пјҢдёҚжҳҫзӨәйҒ®зҪ©еұӮ
			 */
			closeMask() {
				this.maskShow = false
			},
			// TODO nvue еҸ–ж¶ҲеҶ’жіЎ
			clear(e) {

				e.stopPropagation()

				this.clearPropagation = true
			},

			open(direction) {
				// fix by mehaotian еӨ„зҗҶеҝ«йҖҹжү“ејҖе…ій—ӯзҡ„жғ…еҶө
				if (this.showPopup) {
					return
				}
				let innerType = ['top', 'center', 'bottom', 'left', 'right', 'message', 'dialog', 'share']
				if (!(direction && innerType.indexOf(direction) !== -1)) {
					direction = this.mode
				}else {
					this.direction = direction;
				}
				if (!this.config[direction]) {
					return this.$uv.error(`зјәе°‘зұ»еһӢпјҡ${direction}`);
				}
				this[this.config[direction]]()
				this.$emit('change', {
					show: true,
					type: direction
				})
			},
			close(type) {
				this.showTrans = false
				this.$emit('change', {
					show: false,
					type: this.mode
				})
				clearTimeout(this.timer)
				// // иҮӘе®ҡд№үе…ій—ӯдәӢд»¶
				this.timer = setTimeout(() => {
					this.showPopup = false
				}, 300)
			},
			// TODO еӨ„зҗҶеҶ’жіЎдәӢд»¶пјҢеӨҙжқЎзҡ„еҶ’жіЎдәӢд»¶жңүй—®йўҳ пјҢе…Ҳиҝҷж ·е…је®№
			touchstart() {
				this.clearPropagation = false
			},
			onTap() {
				if (this.clearPropagation) {
					// fix by mehaotian е…је®№ nvue
					this.clearPropagation = false
					return
				}
				this.$emit('maskClick')
				if (!this.closeOnClickOverlay) return
				this.close()
			},
			/**
			 * йЎ¶йғЁеј№еҮәж ·ејҸеӨ„зҗҶ
			 */
			top(type) {
				this.popupClass = this.isDesktop ? 'fixforpc-top' : 'top'
				this.ani = ['slide-top']
				this.transitionStyle = {
					position: 'fixed',
					zIndex: this.zIndex,
					left: 0,
					right: 0,
					backgroundColor: this.bg
				}
				// TODO е…је®№ type еұһжҖ§ пјҢеҗҺз»ӯдјҡеәҹејғ
				if (type) return
				this.showPopup = true
				this.showTrans = true
				this.$nextTick(() => {
					if (this.messageChild && this.mode === 'message') {
						this.messageChild.timerClose()
					}
				})
			},
			/**
			 * еә•йғЁеј№еҮәж ·ејҸеӨ„зҗҶ
			 */
			bottom(type) {
				this.popupClass = 'bottom'
				this.ani = ['slide-bottom']
				this.transitionStyle = {
					position: 'fixed',
					zIndex: this.zIndex,
					left: 0,
					right: 0,
					bottom: 0,
					backgroundColor: this.bg
				}
				// TODO е…је®№ type еұһжҖ§ пјҢеҗҺз»ӯдјҡеәҹејғ
				if (type) return
				this.showPopup = true
				this.showTrans = true
			},
			/**
			 * дёӯй—ҙеј№еҮәж ·ејҸеӨ„зҗҶ
			 */
			center(type) {
				this.popupClass = 'center'
				this.ani = this.zoom?['zoom-in', 'fade']:['fade'];
				this.transitionStyle = {
					position: 'fixed',
					zIndex: this.zIndex,

					display: 'flex',
					flexDirection: 'column',

					bottom: 0,
					left: 0,
					right: 0,
					top: 0,
					justifyContent: 'center',
					alignItems: 'center'
				}
				// TODO е…је®№ type еұһжҖ§ пјҢеҗҺз»ӯдјҡеәҹејғ
				if (type) return
				this.showPopup = true
				this.showTrans = true
			},
			left(type) {
				this.popupClass = 'left'
				this.ani = ['slide-left']
				this.transitionStyle = {
					position: 'fixed',
					zIndex: this.zIndex,
					left: 0,
					bottom: 0,
					top: 0,
					backgroundColor: this.bg,

					display: 'flex',
					flexDirection: 'column'

				}
				// TODO е…је®№ type еұһжҖ§ пјҢеҗҺз»ӯдјҡеәҹејғ
				if (type) return
				this.showPopup = true
				this.showTrans = true
			},
			right(type) {
				this.popupClass = 'right'
				this.ani = ['slide-right']
				this.transitionStyle = {
					position: 'fixed',
					zIndex: this.zIndex,
					bottom: 0,
					right: 0,
					top: 0,
					backgroundColor: this.bg,

					display: 'flex',
					flexDirection: 'column'

				}
				// TODO е…је®№ type еұһжҖ§ пјҢеҗҺз»ӯдјҡеәҹејғ
				if (type) return
				this.showPopup = true
				this.showTrans = true
			}
		}
	}
</script>
<style lang="scss" scoped>
	.uv-popup {
		position: fixed;

		z-index: 99;


		&.top,
		&.left,
		&.right {




			top: 0;

		}

		.uv-popup__content {

			display: block;
			overflow: hidden;

			position: relative;

			&.left,
			&.right {




				padding-top: 0;

				flex: 1;
			}
			&__close {
				position: absolute;

				&--hover {
					opacity: 0.4;
				}
			}
			
			&__close--top-left {
				top: 15px;
				left: 15px;
			}
			
			&__close--top-right {
				top: 15px;
				right: 15px;
			}
			
			&__close--bottom-left {
				bottom: 15px;
				left: 15px;
			}
			
			&__close--bottom-right {
				right: 15px;
				bottom: 15px;
			}
		}
	}

	.fixforpc-z-index {

		z-index: 999;

	}

	.fixforpc-top {
		top: 0;
	}
</style>
